import React from "react";

export default function ForecastCard() {
  const dailyForecast = Array.from({ length: 16 }, (_, i) => ({
    day: `Day ${i + 1}`,
    condition: i % 2 === 0 ? "☀️ Sunny" : "🌧 Rainy",
    high: `${30 + (i % 5)}°C`,
    low: `${20 + (i % 5)}°C`,
  }));

  return (
    <div className="w-full max-w-3xl mx-auto mt-8 px-4 pb-20">
      <h2 className="text-2xl font-bold text-center text-white drop-shadow-glow mb-4">
        16-Day Forecast
      </h2>
      <div className="space-y-4">
        {dailyForecast.map((forecast, index) => (
          <div
            key={index}
            className="flex items-center justify-between bg-white/10 backdrop-blur-xl rounded-2xl px-6 py-4 shadow-xl ring-1 ring-white/20 border-t border-white/30"
          >
            <div>
              <p className="text-lg font-semibold text-purple-300 drop-shadow-purple">
                {forecast.day}
              </p>
              <p className="text-sm text-white/70 drop-shadow-glow">
                {forecast.condition}
              </p>
            </div>
            <div className="text-right">
              <p className="text-xl font-bold text-purple-400 drop-shadow-purple">
                {forecast.high}
              </p>
              <p className="text-sm text-white/60">Low: {forecast.low}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
